    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

void collect(TreeNode* node, vector<int> &path, vector<pair<int, vector<int>>> &all)
{
    if (node == nullptr) return;
    path.push_back(node->val);
    if (!node->left && !node->right)
    {
        int sum = 0;
        for (int v : path) sum += v;
        all.push_back({sum, path});
    }
    collect(node->left, path, all);
    collect(node->right, path, all);
    path.pop_back();
}

vector<vector<int>> pathSum(TreeNode* root, int targetSum)
{
    vector<pair<int, vector<int>>> all;
    vector<int> path;
    collect(root, path, all);

    vector<vector<int>> result;
    for (auto &[sum, p] : all) if (sum == targetSum) result.push_back(p);
    return result;
}

