    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

void collectLeaves(TreeNode* node, vector<TreeNode*> &ancestors, vector<vector<TreeNode*>> &leafPaths)
{
    if (node == nullptr) return;
    ancestors.push_back(node);
    if (!node->left && !node->right) leafPaths.push_back(ancestors);
    collectLeaves(node->left, ancestors, leafPaths);
    collectLeaves(node->right, ancestors, leafPaths);
    ancestors.pop_back();
}

vector<string> binaryTreePaths(TreeNode* root)
{
    vector<vector<TreeNode*>> leafPaths;
    vector<TreeNode*> ancestors;
    collectLeaves(root, ancestors, leafPaths);

    vector<string> result;
    for (auto &path : leafPaths)
    {
        string s = to_string(path[0]->val);
        for (int i = 1; i < path.size(); i++) s += "->" + to_string(path[i]->val);
        result.push_back(s);
    }
    return result;
}

int main()
{
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    root->left->right = new TreeNode(5);

    auto result = binaryTreePaths(root);
    for (string &s : result) cout << s << " ";

    return 0;
}

