int best = INT_MIN;

void visit(TreeNode* node)
{
    if (node == nullptr) return;
    int leftSum = max(0, maxDownward(node->left));
    int rightSum = max(0, maxDownward(node->right));
    best = max(best, node->val + leftSum + rightSum);
    visit(node->left);
    visit(node->right);
}

int maxPathSum(TreeNode* root)
{
    best = INT_MIN;
    visit(root);
    return best;
}

